        print("First OK")
        open("firsttask{}.txt".format(self.time),"w+")
    
    def output(self):
        return luigi.LocalTarget("firsttask{}.txt".format(self.time))
        
class second(luigi.Task):
    time = luigi.Parameter()
    
    def run(self):
        print("Second OK")
        open("secondtask{}.txt".format(self.time),"w+")
        
    def requires(self):
        return first(self.time)
    
    def output(self):
        return luigi.LocalTarget("secondtask{}.txt".format(self.time))

class third(luigi.Task):
    time = luigi.Parameter()
    
    def run(self):
        print("Third ok")
        open("thirdtask{}.txt".format(self.time),"w+")
        time.sleep(self.time)
        
