The following code produces a bad color image buffer:
```
  rs::context ctx;
  rs::device & dev = *ctx.get_device(0);

  int width = 640, height = 480;
  dev.enable_stream(rs::stream::color, width, height, rs::format::bgr8, 60);

  // Start our device
  dev.start();

  // Stop our device
  dev.stop();

  width = 1920, height = 1080;
  dev.enable_stream(rs::stream::color, width, height, rs::format::bgr8, 30);

  cv::Mat color_image_hd(height, width, CV_8UC3);

  // Start our device
  dev.start();

  while (true) {
    dev.wait_for_frames();

    memcpy(color_image_hd.data, (uchar *) dev.get_frame_data(rs::stream::color), width*height*3);

    cv::imshow("Color image HD", color_image_hd);
    char c = cv::waitKey(30);
    if (c == 27) {
      break;
    }
  }
```

