```

But this code seems also ok (depth stream without consuming the stream buffer):
```
  rs::context ctx;
  rs::device & dev = *ctx.get_device(0);

  int width = 640, height = 480;
  dev.enable_stream(rs::stream::depth, width, height, rs::format::z16, 60);

