  try {
    dev.enable_stream(rs::stream::depth, width, height, rs::format::z16, 60);
  } catch (std::exception &e) {
    std::cerr << "Exception: " << e.what() << std::endl;
  }

  cv::Mat depth_image(height, width, CV_16S);
  cv::Mat depth_image_display(height, width, CV_8U);

  // Start our device
  dev.start();

  while (true) {
    dev.wait_for_frames();

    memcpy(depth_image.data, (uchar *) dev.get_frame_data(rs::stream::depth), width*height*2);
    depth_image.convertTo(depth_image_display, CV_8U, 0.5);

    cv::imshow("Depth", depth_image_display);
    char c = cv::waitKey(30);
    if (c == 27) {
      break;
    }
  }
```

